(function(w){"use strict";const ID="weight",f={mg:.000001,g:.001,kg:1,lb:.45359237,oz:.028349523125};function compute(x){const v=Number(x.value);if(!Number.isFinite(v)||!f[x.from]||!f[x.to])return{error:"값과 단위를 올바르게 선택해 주세요."};return{value:v*f[x.from]/f[x.to]}}function render(root,api){const opts=`<option value="mg">mg</option><option value="g">g</option><option value="kg" selected>kg</option><option value="lb">lb</option><option value="oz">oz</option>`;root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label>변환할 값</label><input class="hm-calc-input" inputmode="decimal"></div><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>기준 단위</label><select class="hm-calc-select">${opts}</select></div><div class="hm-calc-field"><label>변환 단위</label><select class="hm-calc-select">${opts}</select></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">변환하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const input=root.querySelector("input"),sels=root.querySelectorAll("select"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");sels[1].value="lb";go.addEventListener("click",()=>{const r=compute({value:api.parseNumber(input.value),from:sels[0].value,to:sels[1].value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("변환 결과",`${api.formatNumber(r.value,8)} ${sels[1].value}`));});}w.HM_CALC.register(ID,{compute,render});})(window);
